"use strict";(self.webpackChunkyes_steve_model_wiki_page=self.webpackChunkyes_steve_model_wiki_page||[]).push([[5772],{7701:(e,t,o)=>{o.r(t),o.d(t,{comp:()=>c,data:()=>l});var i=o(641);const a={},c=(0,o(6262).A)(a,[["render",function(e,t){const o=(0,i.g2)("ImageCard");return(0,i.uX)(),(0,i.CE)("div",null,[t[8]||(t[8]=(0,i.Fv)('<p>Yes Steve Model 模组采用了 <code>geckolib</code> 作为核心，所以它支持 <code>geckolib</code> 兼容的<code>基岩版 1.12.0 及以上 </code>版本模型文件和 <code>基岩版 1.8.0 </code>版本动画文件。</p><p>自 2.3.0 版本起，我们还支持基岩版动画控制器和动画音频。</p><h2 id="模型格式" tabindex="-1"><a class="header-anchor" href="#模型格式"><span>模型格式</span></a></h2><p>模型文件有三种格式，这三者放在指定目录下均可被游戏识别加载：</p><ul><li>文件夹格式：对于模型设计者来说最推荐的格式，可以方便的修改内容，并在游戏内快速重载测试；</li><li>压缩包格式：是文件夹格式的<strong>直接打包</strong>，方便分享给他人；</li><li>ysm 格式：是文件夹格式的<strong>加密打包</strong>，方便分享给他人的同时防止模型文件被修改盗用；</li></ul><h2 id="模型文件放哪里" tabindex="-1"><a class="header-anchor" href="#模型文件放哪里"><span>模型文件放哪里</span></a></h2><p>自定义模型文件全部放置在游戏主目录下的 <code>config/yes_steve_model</code> 文件夹下。<code>yes_steve_model</code> 下会自动生成四个文件夹：</p><ul><li><code>auth </code> 文件夹：用来放置自定义模型，该位置的自定义模型<strong>必须授权</strong>后才可以使用。</li><li><code>cache</code> 文件夹：系统自动从服务端获取的加密模型文件缓存文件夹。</li><li><code>custom</code> 文件夹：用来放置自定义模型，该位置的自定义模型<strong>无需授权</strong>就可使用。</li><li><code>export</code> 文件夹：当在游戏内使用了 <code>/ysm export</code> 指令，生成的 <code>ysm</code> 专属格式的模型就在这。</li></ul><p>你可以选择在 <code>auth</code> 或者 <code>custom</code> 文件夹下直接放置自定义模型文件。</p><div class="hint-container tip"><p class="hint-container-title">提示</p><p>2.2.1 版本开始，为了解决众多玩家喜欢修改文件名，或者目录下套多层文件夹的做法。我们修改了文件读取逻辑。</p><p>现在只要是在 <code>custom</code> 或者 <code>auth</code> 目录下，无论套几层子文件夹（最大 16 层），无论是文件夹、压缩包、ysm 格式，都能正确识别。同时文件名支持任意字符（包括中文）。</p></div><h2 id="加密格式说明" tabindex="-1"><a class="header-anchor" href="#加密格式说明"><span>加密格式说明</span></a></h2>',11)),(0,i.Lk)("ul",null,[t[5]||(t[5]=(0,i.Lk)("li",null,[(0,i.eW)("ysm 格式的加密模型无法再转换成普通模型文件，"),(0,i.Lk)("mark",null,"也无法再做二次修改！")],-1)),t[6]||(t[6]=(0,i.Lk)("li",null,"ysm 格式遵循向下兼容的原则，所以如果用高版本模组导出的 ysm 格式，在低版本是无法加载的！",-1)),t[7]||(t[7]=(0,i.Lk)("li",null,[(0,i.eW)("在游戏内输入"),(0,i.Lk)("code",null,"/ysm export <model_id>"),(0,i.eW)(" 指令，即可将某个文件夹格式的模型导出成 ysm 专属模型格式。")],-1)),(0,i.Lk)("li",null,[t[0]||(t[0]=(0,i.eW)("从 2.2.2 版本开始，该指令还支持 ")),t[1]||(t[1]=(0,i.Lk)("code",null,"/ysm export <model_id> [extra_info]",-1)),t[2]||(t[2]=(0,i.eW)(" 形式，你可以在 ")),t[3]||(t[3]=(0,i.Lk)("code",null,"extra_info",-1)),t[4]||(t[4]=(0,i.eW)(" 处添加自定义的文本信息，这样导出的 ysm 文件中也会附加该名称。")),(0,i.bF)(o,{image:"https://s2.loli.net/2025/01/27/S9n5omVqt8bBOjD.png",title:"记事本打开 YSM 模型文件后的样子",description:"当你用原版记事本打开新版本模组（1.2.0 及以后版本）导出的 ysm 文件，你可以看到如下信息。这些信息无法被修改，如果强行修改，模组会拒绝加载此文件。",center:"true",href:"/"})])])])}]]),l=JSON.parse('{"path":"/wiki/type/","title":"模型格式说明","lang":"zh-CN","frontmatter":{"title":"模型格式说明","icon":"material-symbols:deployed-code-outline","createTime":"2025/01/26 22:15:17","permalink":"/wiki/type/","tags":["模型","格式"]},"headers":[],"readingTime":{"minutes":2.53,"words":758},"git":{"updatedTime":1738250423000,"contributors":[{"name":"tartaric_acid","username":"tartaric_acid","email":"baka943@qq.com","commits":3,"avatar":"https://avatars.githubusercontent.com/tartaric_acid?v=4","url":"https://github.com/tartaric_acid"}]},"filePathRelative":"notes/wiki/模型格式说明.md"}')}}]);